import React, { useState, useEffect } from 'react';
import { 
  ArrowUpRight, 
  Download, 
  MapPin, 
  Twitter, 
  Linkedin, 
  Instagram,
  Copy,
  Mail,
  Phone,
  ArrowRight,
  Github,
  ArrowLeft,
  X,
  CheckCircle2,
  Cpu
} from 'lucide-react';
import { 
  PROJECTS, 
  EXPERIENCE, 
  EDUCATION, 
  CERTIFICATIONS, 
  STACK, 
  AWARDS, 
  RECOMMENDATIONS, 
  ARTICLES 
} from './constants';
import { Project } from './types';

function App() {
  const [currentTime, setCurrentTime] = useState("");
  const [view, setView] = useState<'home' | 'projects'>('home');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  useEffect(() => {
    const updateTime = () => {
      const now = new Date();
      setCurrentTime(now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    };
    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (selectedProject) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [selectedProject]);

  const scrollToContact = () => {
    if (view !== 'home') {
      setView('home');
      // Wait for render then scroll
      setTimeout(() => {
        const element = document.getElementById('lets-talk');
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
      }, 100);
    } else {
      const element = document.getElementById('lets-talk');
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
  };

  const ProjectCard = ({ project }: { project: Project }) => (
    <div className="group block bg-card rounded-xl overflow-hidden border border-border hover:border-zinc-600 transition-colors flex flex-col h-full">
      <div className="aspect-[4/3] bg-zinc-800 relative overflow-hidden shrink-0">
        <img src={project.imageUrl} alt={project.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
        <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity" />
      </div>
      <div className="p-5 flex flex-col flex-grow">
        <div className="flex items-start justify-between mb-4">
          <div>
            <h3 className="font-medium text-lg text-primary">{project.title}</h3>
            <p className="text-sm text-secondary mt-0.5">{project.category}</p>
          </div>
          <a href={project.link} className="text-tertiary hover:text-primary transition-colors">
             <ArrowUpRight className="w-5 h-5" />
          </a>
        </div>

        <div className="mt-auto">
          <button 
            onClick={(e) => {
              e.preventDefault();
              setSelectedProject(project);
            }}
            className="w-full py-2.5 px-4 bg-zinc-900 hover:bg-zinc-800 text-sm font-medium text-secondary hover:text-white rounded-lg transition-colors border border-border"
          >
            View Details
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-background text-primary selection:bg-zinc-800 selection:text-white font-sans">
      {/* Project Modal */}
      {selectedProject && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
          <div 
            className="absolute inset-0 bg-black/80 backdrop-blur-sm"
            onClick={() => setSelectedProject(null)}
          ></div>
          <div className="relative w-full max-w-2xl bg-card border border-border rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="absolute top-4 right-4 z-10">
              <button 
                onClick={() => setSelectedProject(null)}
                className="p-2 bg-black/50 hover:bg-black/70 rounded-full text-white backdrop-blur-md transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="h-48 sm:h-64 bg-zinc-800 shrink-0 relative">
              <img 
                src={selectedProject.imageUrl} 
                alt={selectedProject.title} 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-card to-transparent"></div>
              <div className="absolute bottom-6 left-6 right-6">
                <h2 className="text-2xl sm:text-3xl font-bold text-white">{selectedProject.title}</h2>
                <p className="text-secondary mt-1">{selectedProject.category}</p>
              </div>
            </div>

            <div className="p-6 overflow-y-auto custom-scrollbar space-y-8">
              {/* Key Features */}
              {selectedProject.keyFeatures && (
                <div>
                  <h3 className="text-sm font-semibold text-tertiary uppercase tracking-wider mb-3 flex items-center gap-2">
                    <CheckCircle2 className="w-4 h-4" /> Key Features
                  </h3>
                  <ul className="grid grid-cols-1 gap-2.5">
                    {selectedProject.keyFeatures.map((feature, idx) => (
                      <li key={idx} className="flex items-start gap-3 text-secondary">
                        <span className="w-1.5 h-1.5 rounded-full bg-zinc-600 mt-2 shrink-0"></span>
                        <span className="leading-relaxed">{feature}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              {/* Impact */}
              {selectedProject.impact && (
                <div>
                  <h3 className="text-sm font-semibold text-tertiary uppercase tracking-wider mb-3">Impact</h3>
                  <div className="p-4 bg-zinc-900/50 rounded-lg border border-border">
                    <p className="text-secondary leading-relaxed">
                      {selectedProject.impact}
                    </p>
                  </div>
                </div>
              )}

              {/* Tech Stack */}
              {selectedProject.techStack && (
                <div>
                  <h3 className="text-sm font-semibold text-tertiary uppercase tracking-wider mb-3 flex items-center gap-2">
                    <Cpu className="w-4 h-4" /> Tech Stack
                  </h3>
                  <div className="flex flex-wrap gap-2">
                    {selectedProject.techStack.map((tech, idx) => (
                      <span 
                        key={idx} 
                        className="px-3 py-1 bg-zinc-900 border border-border rounded-full text-sm text-secondary"
                      >
                        {tech}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="p-6 border-t border-border bg-card shrink-0">
              <a 
                href={selectedProject.link} 
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center justify-center gap-2 w-full py-3 bg-white text-black font-medium rounded-lg hover:bg-zinc-200 transition-colors"
              >
                <span>View Live Project</span>
                <ArrowUpRight className="w-4 h-4" />
              </a>
            </div>
          </div>
        </div>
      )}

      {view === 'projects' ? (
        <div className="max-w-[850px] mx-auto px-4 md:px-6 py-12 md:py-20 flex flex-col gap-8">
          <button 
            onClick={() => setView('home')}
            className="flex items-center gap-2 text-sm text-secondary hover:text-white transition-colors w-fit group"
          >
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
            <span>Back to Home</span>
          </button>

          <div className="flex flex-col gap-2 mb-4">
            <h1 className="text-3xl md:text-4xl font-semibold tracking-tight">All Projects</h1>
            <p className="text-lg text-secondary">A collection of my work in automation and AI solutions.</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {PROJECTS.map((project, index) => (
              <ProjectCard key={index} project={project} />
